mapper.select:
    select VC_CODE, VC_NAME, VC_SCODE, C.VC_ITEM_NAME AS KIND_NAME, B.VC_ITEM_NAME AS MARKET_NAME
	  from BSC_SECURITY A, 
	       (SELECT VC_ITEM_VALUE,VC_ITEM_NAME FROM T_BASE_DICTIONARY WHERE l_dictionary_no = 100005) B, 
				 (SELECT VC_ITEM_VALUE,VC_ITEM_NAME FROM T_BASE_DICTIONARY WHERE l_dictionary_no = 100006) C
	WHERE TO_CHAR(A.L_MARKET) = B.VC_ITEM_VALUE
	  AND A.VC_KIND = C.VC_ITEM_VALUE

        and A.VC_CODE LIKE CONCAT(#{secCode}, '%')


        and A.VC_NAME LIKE CONCAT(#{secName}, '%')


        and A.L_MARKET = #{transMarket}


        and A.VC_KIND = #{secType}

SELECT DISTINCT VC_CODE, VC_INTER_CODE, VC_NAME, VC_SCODE, C.VC_ITEM_NAME AS KIND_NAME, B.VC_ITEM_NAME AS MARKET_NAME FROM BSC_SECURITY A LEFT JOIN ( SELECT VC_ITEM_VALUE, VC_ITEM_NAME FROM T_BASE_DICTIONARY WHERE l_dictionary_no = 100005 ) B ON TO_CHAR (A.L_MARKET) = B.VC_ITEM_VALUE LEFT JOIN ( SELECT VC_ITEM_VALUE, VC_ITEM_NAME FROM T_BASE_DICTIONARY WHERE l_dictionary_no = 100006 ) C ON A.VC_KIND = C.VC_ITEM_VALUE
and A.VC_CODE LIKE CONCAT(#{secCode}, '%')
and A.VC_NAME LIKE CONCAT(#{secName}, '%')
and A.L_MARKET = #{transMarket}
and A.VC_KIND = #{secType}
